const raw = ($json.target_reference || '').toLowerCase().trim();

let meal_type = null;

if (raw.match(/\bbreakfast\b/)) meal_type = 'breakfast';
else if (raw.match(/\blunch\b/)) meal_type = 'lunch';
else if (raw.match(/\bdinner\b/)) meal_type = 'dinner';
else if (raw.match(/\bsnack\b|\bsnacks\b/)) meal_type = 'snack';

return [
  {
    json: {
      ...$json,
      delete_meal_type: meal_type
    }
  }
];

const meals = items.map(i => i.json);

// sort
meals.sort((a, b) => new Date(a.logged_at) - new Date(b.logged_at));

// group
const groups = {
  breakfast: [],
  lunch: [],
  dinner: [],
  snack: [],
  other: []
};

for (const m of meals) {
  const label = m.meal_time_label || "other";

  const time = new Date(m.logged_at).toLocaleTimeString('en-IN', {
    timeZone: 'Asia/Kolkata',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true
  });

  const line = `• ${time} — ${m.meal_text}`;

  if (groups[label]) {
    groups[label].push(line);
  } else {
    groups.other.push(line);
  }
}

// build output
let text = "Today's Meals:\n";

for (const key of ["breakfast", "lunch", "dinner", "snack", "other"]) {
  if (groups[key].length > 0) {
    const title = key.charAt(0).toUpperCase() + key.slice(1);
    text += `\n${title}:\n${groups[key].join('\n')}\n`;
  }
}

if (meals.length === 0) {
  text = "No meals logged today.";
}

return [{ json: { text } }];
